('YBM_2020_parent', 'YBM', 2020, 'parent', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('YBM_2018_consolidated', 'YBM', 2018, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'unqualified', 0, NULL),
('YBM_2019_consolidated', 'YBM', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C (Baker Tilly A&C)', 'qualified', 0, NULL),
('YBM_2018_parent', 'YBM', 2018, 'parent', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'unqualified', 0, NULL),
('YEG_2019_consolidated', 'YEG', 2019, 'consolidated', 'PwC (Việt Nam)', 'unqualified', 0, NULL),
('YBM_2019_parent', 'YBM', 2019, 'parent', 'Baker Tilly A&C', 'qualified', 0, NULL),
('YEG_2015_consolidated', 'YEG', 2015, 'consolidated', 'PricewaterhouseCoopers Vietnam', 'unqualified', 0, NULL),
('YBM_2022_parent', 'YBM', 2022, 'parent', 'A&C Auditing and Consulting Co., Ltd.', 'qualified', 0, NULL),
('YBC_2024_consolidated', 'YBC', 2024, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2024 nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 122.062.672.040 đồng.'),
('YBM_2017_parent', 'YBM', 2017, 'parent', 'Công ty TNHH Kiểm toán AFC Việt Nam - Chi nhánh Hà Thành', 'unqualified', 0, NULL),
('YBC_2020_consolidated', 'YBC', 2020, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2020 khoản lỗ lũy kế của Công ty là 30.144.912.607 đồng chiếm 25,5% vốn đầu tư của chủ sở hữu và nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 253.256.136.160 đồng. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('YBC_2022_consolidated', 'YBC', 2022, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2022 khoản lỗ lũy kế của Công ty là 20.570.052.068 đồng chiếm 17,43% vốn đầu tư của chủ sở hữu và nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 185.698.894.745 đồng. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('YBC_2021_consolidated', 'YBC', 2021, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31/12/2021, khoản lỗ lũy kế là 28.078.526.667 đồng chiếm 23,80% vốn chủ sở hữu, nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 190.595.736.428 đồng. Tuy nhiên Công ty vẫn đang có lãi, có chiều hướng phát triển tích cực và tiếp tục được BIDV CN Yên Bái, Agribank CN Yên Bình cho vay. Ban Giám đốc và kiểm toán viên đánh giá giả định hoạt động liên tục vẫn phù hợp.'),
('YBC_2017_consolidated', 'YBC', 2017, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2017 khoản lỗ lũy kế của Công ty là 37.284.536.814 đồng chiếm 63,87% vốn đầu tư của chủ sở hữu và nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 251.632.180.533 đồng. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('YBC_2019_consolidated', 'YBC', 2019, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2019 khoản lỗ lũy kế của Công ty là 31.741.912.229 đồng chiếm 26,9%vốn đầu tư của chủ sở hữu và nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 243.136.114.987 đồng. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty. Ban Giám đốc cho rằng việc lập Báo cáo tài chính theo giả định Hoạt động liên tục vẫn là phù hợp.'),
('YBC_2018_consolidated', 'YBC', 2018, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2018 khoản lỗ lũy kế của Công ty là 33.129.779.373 đồng chiếm 44,5% vốn đầu tư của chủ sở hữu và nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 221.548.755.037 đồng. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('XPH_2024_consolidated', 'XPH', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
('XPH_2023_consolidated', 'XPH', 2023, 'consolidated', 'AASC Auditing Firm', 'unqualified', 0, NULL),
('XPH_2025_consolidated', 'XPH', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam', 'unqualified', 0, NULL),
('XPH_2020_consolidated', 'XPH', 2020, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL);
