('XDH_2019_consolidated', 'XDH', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Định giá Việt Nam', 'unqualified', 0, NULL),
('XLV_2024_consolidated', 'XLV', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('X77_2025_consolidated', 'X77', 2025, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'qualified', 1, 'Nợ ngắn hạn vượt tài sản ngắn hạn 195.302.941.793 đồng; lỗ lũy kế vượt vốn chủ sở hữu 192.684.589.237 đồng; các khoản công nợ phải trả đã quá hạn thanh toán.'),
('XDH_2018_consolidated', 'XDH', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Định giá Việt Nam', 'unqualified', 0, NULL),
('X77_2024_consolidated', 'X77', 2024, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'qualified', 1, 'Tại ngày 31/12/2024, nợ ngắn hạn vượt tài sản ngắn hạn 195.332.273.164 đồng; lỗ lũy kế vượt vốn chủ sở hữu 191.334.155.627 đồng; các khoản công nợ đã quá hạn thanh toán. Khả năng hoạt động liên tục phụ thuộc vào kế hoạch thu hồi công nợ, hỗ trợ tài chính từ cổ đông và chủ nợ.'),
('X77_2023_consolidated', 'X77', 2023, 'consolidated', 'Công ty TNHH Kiểm toán Quốc tế (iCPA)', 'qualified', 1, 'Tại ngày 31/12/2023, nợ ngắn hạn vượt tài sản ngắn hạn 196.673.653.540 đồng; lỗ lũy kế vượt vốn chủ sở hữu 191.280.131.584 đồng; các khoản công nợ phải trả đã quá hạn thanh toán. Khả năng hoạt động liên tục phụ thuộc vào kế hoạch thu hồi công nợ, hỗ trợ tài chính từ cổ đông và chủ nợ. Kiểm toán viên không thu thập đủ bằng chứng về tính khả thi của các kế hoạch này.'),
('X77_2020_consolidated', 'X77', 2020, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 1, 'Tại thời điểm 31/12/2020, Công ty đã ngừng các hoạt động chính, giảm phần lớn số lượng lao động, kết quả kinh doanh trong năm lỗ 8.37 tỷ đồng, lỗ lũy kế vượt quá vốn chủ sở hữu hơn 14 lần, nợ ngắn hạn lớn hơn tài sản ngắn hạn 147 tỷ đồng, ảnh hưởng lớn đến khả năng thanh toán của Công ty.'),
('X77_2019_consolidated', 'X77', 2019, 'consolidated', 'CPA VIETNAM', 'qualified', 1, 'Công ty đã ngừng các hoạt động chính, giảm phần lớn số lượng lao động, kết quả kinh doanh trong năm lỗ 9,66 tỷ đồng, lỗ lũy kế vượt quá vốn chủ sở hữu gần 14 lần, nợ ngắn hạn lớn hơn tài sản ngắn hạn 149 tỷ đồng ảnh hưởng lớn đến khả năng thanh toán của Công ty.'),
('X77_2021_consolidated', 'X77', 2021, 'consolidated', 'CPA VIETNAM', 'qualified', 1, 'Công ty đã ngừng các hoạt động chính, giảm phần lớn số lượng lao động, kết quả kinh doanh trong năm lỗ 7,8 tỷ đồng, lỗ lũy kế vượt quá vốn chủ sở hữu hơn 14 lần, nợ ngắn hạn vượt quá tài sản ngắn hạn 146,4 tỷ đồng, ảnh hưởng lớn đến khả năng thanh toán của Công ty.');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('X77_2018_consolidated', 'X77', 2018, 'consolidated', 'CPA VIETNAM', 'qualified', 1, 'Tại thời điểm 31/12/2018, công ty đã ngừng các hoạt động chính, giảm phần lớn số lượng lao động, kết quả kinh doanh trong năm lỗ 9,63 tỷ đồng, lỗ lũy kế vượt quá vốn chủ sở hữu gần 13 lần, nợ ngắn hạn lớn hơn tài sản ngắn hạn 149 tỷ đồng, ảnh hưởng lớn đến khả năng thanh toán của Công ty.'),
('X77_2015_consolidated', 'X77', 2015, 'consolidated', 'Công ty TNHH Kiểm toán Hùng Vương', 'qualified', 1, 'Số lỗ lũy kế tính đến ngày 31/12/2015 là 24.547.264.737 đ, vốn chủ sở hữu của Công ty tại ngày 31/12/2015 là -11.633.461.530 đ, tuy nhiên, tính liên tục hoạt động phụ thuộc vào khả năng duy trì, thanh toán các khoản nợ, sự trợ giúp tài chính từ phía chủ đầu tư và khả năng tìm kiếm, mở rộng thị trường tiêu thụ sản phẩm trong tương lai gần.'),
('XMC_2015_consolidated', 'XMC', 2015, 'consolidated', 'Chi nhánh Công ty TNHH Dịch vụ Tư vấn Tài chính Kế toán và Kiểm toán Nam Việt (AASCN)', 'unqualified', 0, NULL),
('YBC_2025_consolidated', 'YBC', 2025, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt – Chi nhánh tại Hà Nội', 'unqualified', 1, 'Tại ngày 31 tháng 12 năm 2025, nợ ngắn hạn vượt quá tổng tài sản ngắn hạn là 105.573.612.032 đồng, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục. Tuy nhiên, Công ty vẫn đang có lãi, tiếp tục được các Ngân hàng TMCP Đầu tư và Phát triển Việt Nam - CN Yên Bái và Ngân hàng Nông nghiệp và Phát triển Nông thôn Việt Nam – CN huyện Yên Bình Bắc Yên Bái cho vay. Ban Giám đốc cho rằng các vấn đề trên sẽ không ảnh hưởng đến tính hoạt động liên tục của Công ty.'),
('X26_2023_consolidated', 'X26', 2023, 'consolidated', 'An Việt', 'unqualified', 0, NULL),
('X26_2024_consolidated', 'X26', 2024, 'consolidated', 'CÔNG TY TNHH KIỂM TOÁN VÀ ĐỊNH GIÁ VIỆT NAM', 'unqualified', 0, NULL),
